command:
// Award a Session Beat to every selected token.
// Prompts once for the session number, then adds a single Beat to each
// selected actor with name "Session <N>".
const tokens = canvas.tokens?.controlled ?? [];
if (!tokens.length) {
  ui.notifications.warn("Select at least one token first.");
  return;
}
new foundry.appv1.api.Dialog({
  title: "Award Session Beat",
  content: `
    <form>
      <div class="form-group">
        <label>Session number</label>
        <input type="number" name="session" min="1" step="1" value="1" autofocus>
      </div>
    </form>`,
  buttons: {
    award: {
      icon: '<i class="fas fa-check"></i>',
      label: "Award",
      callback: async (html) => {
        const raw = html.find('input[name="session"]').val();
        const n = Math.max(1, Math.floor(Number(raw) || 0));
        const label = `Session ${n}`;
        const awarded = [];
        for (const token of tokens) {
          const actor = token.actor;
          if (!actor) continue;
          await actor.addProgress(label, 1, 0);
          awarded.push(actor.name);
        }
        if (awarded.length) {
          const list = awarded.map(a => `<li>${a}</li>`).join("");
          await ChatMessage.create({
            user: game.user.id,
            speaker: { alias: "Storyteller" },
            content: `<p><strong>${label}</strong> Beat awarded to:</p><ul>${list}</ul>`
          });
        }
      }
    },
    cancel: { icon: '<i class="fas fa-times"></i>', label: "Cancel" }
  },
  default: "award"
}).render(true);
